-- statement-store: primary
-- description: Recent denormalized statement rows for UI preview, limited for fast rendering

with statement_roots_agg as ( select sr.statement_fingerprint, array_agg(sr.root order by sr.root) as roots, count(*) as root_count from statement_roots sr group by sr.statement_fingerprint ) select s.statement_fingerprint, s.created_at, s.subject_type, s.subject_reference_type, subj.reference_identifier as subject_reference_identifier, pred.reference_identifier as predicate_reference_identifier, s.object_type, s.object_reference_type, obj.reference_identifier as object_reference_identifier, coalesce(r.roots, array[]::text[]) as roots, coalesce(r.root_count, 0) as root_count from statements s inner join reference_identifiers subj on subj.identifier_fingerprint = s.subject_fingerprint inner join reference_identifiers pred on pred.identifier_fingerprint = s.predicate_fingerprint inner join reference_identifiers obj on obj.identifier_fingerprint = s.object_fingerprint left join statement_roots_agg r on r.statement_fingerprint = s.statement_fingerprint order by s.created_at desc, s.statement_fingerprint asc limit 50
